from typing import List

class Solution:
    def canAliceWin(self, a: List[str], b: List[str]) -> bool:
        def find_next_word(word_list, current_word):
            # Binary search to find the next valid word
            left, right = 0, len(word_list)
            while left < right:
                mid = (left + right) // 2
                if word_list[mid] > current_word:
                    right = mid
                else:
                    left = mid + 1
            # Check if the found word is closely greater
            if left < len(word_list):
                next_word = word_list[left]
                if next_word[0] == current_word[0] or (ord(next_word[0]) == ord(current_word[0]) + 1):
                    return left
            return -1

        # Initialize pointers for both lists
        a_index, b_index = 0, 0
        current_word = a[0]  # Alice starts with the smallest word in her list
        alice_turn = False  # Alice starts, so next turn is Bob's

        while True:
            if alice_turn:
                next_index = find_next_word(a, current_word)
                if next_index == -1:
                    return False  # Alice cannot play, she loses
                current_word = a[next_index]
                a_index = next_index + 1
            else:
                next_index = find_next_word(b, current_word)
                if next_index == -1:
                    return True  # Bob cannot play, Alice wins
                current_word = b[next_index]
                b_index = next_index + 1
            alice_turn = not alice_turn

