from typing import List

class Solution:
    def canAliceWin(self, a: List[str], b: List[str]) -> bool:
        def can_play(word, last_word):
            if word > last_word and (word[0] == last_word[0] or ord(word[0]) == ord(last_word[0]) + 1):
                return True
            return False

        a_idx, b_idx = 0, 0
        turn = 0  # 0 for Alice, 1 for Bob
        last_word = a[0]  # Alice starts with her smallest word
        a_idx += 1

        while a_idx < len(a) or b_idx < len(b):
            if turn == 0:  # Alice's turn
                while a_idx < len(a) and not can_play(a[a_idx], last_word):
                    a_idx += 1
                if a_idx == len(a):  # Alice cannot play
                    return False
                last_word = a[a_idx]
                a_idx += 1
            else:  # Bob's turn
                while b_idx < len(b) and not can_play(b[b_idx], last_word):
                    b_idx += 1
                if b_idx == len(b):  # Bob cannot play
                    return True
                last_word = b[b_idx]
                b_idx += 1
            turn = 1 - turn  # Switch turns

        return turn == 1  # If it's Bob's turn and no one can play, Alice wins

