from typing import List
from bisect import bisect_left

class Solution:
    def canAliceWin(self, a: List[str], b: List[str]) -> bool:
        def find_next_word(word_list, prev_word):
            """Find the next valid word in the list that is closely greater than prev_word."""
            start_char = prev_word[0]
            next_char = chr(ord(start_char) + 1) if start_char < 'z' else None
            candidates = [prev_word[0], next_char] if next_char else [prev_word[0]]

            for candidate in candidates:
                # Construct a dummy word to find the lower bound
                dummy_word = candidate + prev_word[1:]
                idx = bisect_left(word_list, dummy_word)
                if idx < len(word_list) and word_list[idx][0] == candidate and word_list[idx] > prev_word:
                    return idx
            return -1

        # Pointers for Alice and Bob's lists
        a_ptr, b_ptr = 0, 0
        turn = 0  # 0 for Alice, 1 for Bob
        prev_word = a[0]  # Alice starts with the smallest word in her list

        while True:
            if turn == 0:  # Alice's turn
                next_idx = find_next_word(a, prev_word)
                if next_idx == -1:
                    return False  # Alice cannot play, she loses
                prev_word = a[next_idx]
                a_ptr = next_idx + 1
            else:  # Bob's turn
                next_idx = find_next_word(b, prev_word)
                if next_idx == -1:
                    return True  # Bob cannot play, Alice wins
                prev_word = b[next_idx]
                b_ptr = next_idx + 1

            turn = 1 - turn  # Switch turns

