from typing import List

class Solution:
    def canAliceWin(self, a: List[str], b: List[str]) -> bool:
        def find_next_move(player_words, last_word):
            """Find the lexicographically smallest word in player_words that is closely greater than last_word."""
            for word in player_words:
                if word > last_word and (word[0] == last_word[0] or ord(word[0]) == ord(last_word[0]) + 1):
                    return word
            return None  # No valid move found

        a_index, b_index = 0, 0
        last_word = a[0]  # Alice plays the smallest word to start the game
        alice_turn = False  # After the first turn, it will be Bob's turn

        while True:
            if alice_turn:
                next_word = find_next_move(a[a_index:], last_word)  # Alice's turn, search her words
                if not next_word:  # If Alice cannot make a move, she loses
                    return False
                # Update last_word and a_index
                last_word = next_word
                a_index = a.index(next_word) + 1
            else:
                next_word = find_next_move(b[b_index:], last_word)  # Bob's turn, search his words
                if not next_word:  # If Bob cannot make a move, Alice wins
                    return True
                # Update last_word and b_index
                last_word = next_word
                b_index = b.index(next_word) + 1

            # Switch turn
            alice_turn = not alice_turn

