class Solution:
    def getMaximumConsecutive(self, coins: List[int]) -> int:
        # Sort the coins in ascending order
        coins.sort()

        # Initialize the maximum consecutive sum we can form
        max_consecutive = 0

        # Iterate over each coin in the sorted list
        for coin in coins:
            # If the coin is greater than max_consecutive + 1, we have a gap
            if coin > max_consecutive + 1:
                break
            # Otherwise, add the value of the coin to max_consecutive
            max_consecutive += coin

        # The maximum number of consecutive integers we can form
        return max_consecutive + 1

