class Solution:
    def findPaths(self, m: int, n: int, maxMove: int, startRow: int, startColumn: int) -> int:
        MOD = 10**9 + 7

        # Initialize a 3D DP array
        dp = [[[0] * n for _ in range(m)] for _ in range(maxMove + 1)]

        # Directions for moving the ball
        directions = [(1, 0), (-1, 0), (0, 1), (0, -1)]

        # Base case: 0 moves, no paths
        dp[0][startRow][startColumn] = 1

        # Calculate paths for each move
        for move in range(1, maxMove + 1):
            for i in range(m):
                for j in range(n):
                    for di, dj in directions:
                        ni, nj = i + di, j + dj
                        if 0 <= ni < m and 0 <= nj < n:
                            dp[move][i][j] = (dp[move][i][j] + dp[move - 1][ni][nj]) % MOD
                        else:
                            dp[move][i][j] = (dp[move][i][j] + 1) % MOD

        # Sum up all paths that lead to exiting the grid
        result = 0
        for move in range(1, maxMove + 1):
            for i in range(m):
                result = (result + dp[move][i][0]) % MOD
                result = (result + dp[move][i][n - 1]) % MOD
            for j in range(n):
                result = (result + dp[move][0][j]) % MOD
                result = (result + dp[move][m - 1][j]) % MOD

        return result

