from typing import List

class Solution:
    def minOperations(self, nums: List[int]) -> int:
        max_doubling = 0
        total_increments = 0

        for num in nums:
            doubling = 0
            while num > 0:
                if num % 2 == 1:
                    total_increments += 1
                    num -= 1
                else:
                    doubling += 1
                    num //= 2
            max_doubling = max(max_doubling, doubling)

        return total_increments + max_doubling

