class Solution:
    def strobogrammaticInRange(self, low: str, high: str) -> int:
        def is_valid(num):
            return low <= num <= high

        def build_strobogrammatic(current, n):
            if len(current) == n:
                num = "".join(current)
                if is_valid(num):
                    return 1
                return 0

            count = 0
            for a, b in pairs:
                if len(current) == 0 and n > 1 and a == '0':  # Skip leading zeros
                    continue
                if len(current) == n // 2 and n % 2 == 1 and a != b:  # Skip invalid middle digits
                    continue
                current.append(a)
                current.insert(0, b)
                count += build_strobogrammatic(current, n)
                current.pop(0)
                current.pop()
            return count

        def count_strobogrammatic(n):
            return build_strobogrammatic([], n)

        pairs = [('0', '0'), ('1', '1'), ('6', '9'), ('8', '8'), ('9', '6')]
        total_count = 0
        for length in range(len(low), len(high) + 1):
            total_count += count_strobogrammatic(length)
        return total_count

