class Solution:
    def longestIdealString(self, s: str, k: int) -> int:
        # Initialize a dp array to store the maximum length of ideal strings ending with each character
        dp = [0] * 26  # 26 letters in the alphabet

        for char in s:
            idx = ord(char) - ord('a')  # Get the index of the current character
            max_length = 0

            # Check all characters within the range of k difference
            for i in range(max(0, idx - k), min(25, idx + k) + 1):
                max_length = max(max_length, dp[i])

            # Update the dp array for the current character
            dp[idx] = max_length + 1

        # The result is the maximum value in the dp array
        return max(dp)

