class Solution:
    def longestIdealString(self, s: str, k: int) -> int:
        # Initialize a dictionary to store the longest ideal subsequence length ending with each character
        dp = {}

        # Iterate over each character in the string
        for char in s:
            # Get the ASCII value of the current character
            char_val = ord(char)

            # Initialize the maximum length for the current character
            max_length = 0

            # Check all characters within the range [char - k, char + k]
            for diff in range(-k, k + 1):
                # Calculate the neighboring character's ASCII value
                neighbor_val = char_val + diff

                # If the neighboring character is a valid lowercase letter
                if ord('a') <= neighbor_val <= ord('z'):
                    # Update the maximum length considering the neighbor
                    max_length = max(max_length, dp.get(chr(neighbor_val), 0))

            # Update the dp dictionary for the current character
            dp[char] = max_length + 1

        # Return the maximum value in the dp dictionary
        return max(dp.values())

