# Candidate 7
class Solution:
    def makeConnected(self, n: int, connections: List[List[int]]) -> int:
        # If there are less than n-1 connections, it's impossible to connect all computers
        if len(connections) < n - 1:
            return -1

        # Initialize parent and rank for union-find
        parent = list(range(n))
        rank = [0] * n

        # Union-find helper functions
        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])  # Path compression
            return parent[x]

        def union(x, y):
            root_x = find(x)
            root_y = find(y)

            if root_x != root_y:
                # Union by rank
                if rank[root_x] > rank[root_y]:
                    parent[root_y] = root_x
                elif rank[root_x] < rank[root_y]:
                    parent[root_x] = root_y
                else:
                    parent[root_y] = root_x
                    rank[root_x] += 1

        # Perform union operations for all connections
        for a, b in connections:
            union(a, b)

        # Count the number of disconnected components
        components = sum(1 for i in range(n) if find(i) == i)

        # Minimum number of operations needed is components - 1
        return components - 1
